import numpy as np
from typing import Callable, List, Dict, Tuple, Any, Union, Optional
from dataclasses import dataclass, field
from itertools import product
from collections import defaultdict

@dataclass
class HyperparameterDef:
    name: str
    param_type: str
    low: Optional[float] = None
    high: Optional[float] = None
    values: Optional[List[Any]] = None
    log_scale: bool = False

class HyperparameterSpace:
    def __init__(self):
        self.params: Dict[str, HyperparameterDef] = {}

    def add_continuous(self, name: str, low: float, high: float, log_scale: bool = False):
        self.params[name] = HyperparameterDef(
            name=name,
            param_type="continuous",
            low=low,
            high=high,
            log_scale=log_scale
        )
        return self

    def add_discrete(self, name: str, values: List[float]):
        self.params[name] = HyperparameterDef(
            name=name,
            param_type="discrete",
            values=values
        )
        return self

    def add_categorical(self, name: str, values: List[Any]):
        self.params[name] = HyperparameterDef(
            name=name,
            param_type="categorical",
            values=values
        )
        return self

    def sample_random(self) -> Dict[str, Any]:
        config = {}
        for name, param in self.params.items():
            if param.param_type == "continuous":
                if param.log_scale:
                    log_val = np.random.uniform(np.log(param.low), np.log(param.high))
                    config[name] = np.exp(log_val)
                else:
                    config[name] = np.random.uniform(param.low, param.high)
            elif param.param_type in ["discrete", "categorical"]:
                config[name] = np.random.choice(param.values)
        return config

    def get_grid(self) -> List[Dict[str, Any]]:
        grid_params = {}
        for name, param in self.params.items():
            if param.param_type in ["discrete", "categorical"]:
                grid_params[name] = param.values
            elif param.param_type == "continuous":
                # Sample 5 points for continuous
                if param.log_scale:
                    grid_params[name] = np.logspace(
                        np.log10(param.low), np.log10(param.high), 5
                    ).tolist()
                else:
                    grid_params[name] = np.linspace(param.low, param.high, 5).tolist()

        keys = list(grid_params.keys())
        values = list(grid_params.values())

        return [dict(zip(keys, combo)) for combo in product(*values)]

@dataclass
class TuningResult:
    config: Dict[str, Any]
    mean_cost: float
    std_cost: float
    all_costs: List[float]
    num_evaluations: int

class HyperparameterTuner:
    def __init__(
        self,
        space: HyperparameterSpace,
        cost_function: Callable[[np.ndarray], float],
        optimizer_class: type,
        num_seeds: int = 5
    ):
        self.space = space
        self.cost_function = cost_function
        self.optimizer_class = optimizer_class
        self.num_seeds = num_seeds
        self.results: List[TuningResult] = []

    def evaluate_config(
        self,
        config: Dict[str, Any],
        initial_params: np.ndarray
    ) -> TuningResult:
        costs = []
        total_evals = 0

        for seed in range(self.num_seeds):
            np.random.seed(seed)

            # Add some perturbation to initial params
            perturbed_init = initial_params + np.random.normal(0, 0.1, len(initial_params))

            try:
                optimizer = self.optimizer_class(**config)
                if hasattr(optimizer, 'optimize'):
                    result = optimizer.optimize(self.cost_function, perturbed_init)
                    if isinstance(result, tuple):
                        _, final_cost = result
                    else:
                        final_cost = result.get('optimal_cost', result)
                else:
                    # Scipy-style
                    from scipy.optimize import minimize
                    result = minimize(
                        self.cost_function,
                        perturbed_init,
                        **config
                    )
                    final_cost = result.fun

                costs.append(final_cost)
            except Exception as e:
                costs.append(float('inf'))

        result = TuningResult(
            config=config.copy(),
            mean_cost=np.mean(costs),
            std_cost=np.std(costs),
            all_costs=costs,
            num_evaluations=self.num_seeds
        )

        self.results.append(result)
        return result

    def grid_search(
        self,
        initial_params: np.ndarray
    ) -> TuningResult:
        grid = self.space.get_grid()

        for config in grid:
            self.evaluate_config(config, initial_params)

        return self.get_best_config()

    def random_search(
        self,
        initial_params: np.ndarray,
        n_samples: int = 50
    ) -> TuningResult:
        for _ in range(n_samples):
            config = self.space.sample_random()
            self.evaluate_config(config, initial_params)

        return self.get_best_config()

    def get_best_config(self) -> TuningResult:
        if not self.results:
            return None
        return min(self.results, key=lambda r: r.mean_cost)

    def analyze_results(self) -> Dict[str, Any]:
        if not self.results:
            return {}

        all_costs = [r.mean_cost for r in self.results]

        # Parameter importance (variance of mean cost when param changes)
        param_importance = {}
        for param_name in self.space.params.keys():
            param_values = defaultdict(list)
            for r in self.results:
                val = r.config.get(param_name)
                param_values[val].append(r.mean_cost)

            # Variance across parameter values
            means = [np.mean(costs) for costs in param_values.values()]
            param_importance[param_name] = np.var(means) if len(means) > 1 else 0

        # Normalize importance
        total = sum(param_importance.values()) + 1e-10
        param_importance = {k: v/total for k, v in param_importance.items()}

        return {
            'num_configs_tested': len(self.results),
            'best_cost': min(all_costs),
            'worst_cost': max(all_costs),
            'mean_cost': np.mean(all_costs),
            'std_cost': np.std(all_costs),
            'parameter_importance': param_importance,
            'best_config': self.get_best_config().config
        }
